namespace RecipeShare.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new() { Id = 1, Title = "Classic Pancakes", Category = "Breakfast", Ingredients = "Flour, Eggs, Milk, Butter, Sugar, Baking powder", Steps = "1. Mix dry ingredients\n2. Whisk wet ingredients\n3. Combine and stir until smooth\n4. Cook on griddle until golden", Ratings = [4, 5, 4] },
        new() { Id = 2, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce, Parmesan, Croutons, Caesar dressing, Lemon", Steps = "1. Wash and chop lettuce\n2. Prepare dressing\n3. Toss lettuce with dressing\n4. Top with croutons and parmesan", Ratings = [5, 4, 5] },
        new() { Id = 3, Title = "Spaghetti Carbonara", Category = "Pasta", Ingredients = "Spaghetti, Eggs, Pecorino Romano, Guanciale, Black pepper", Steps = "1. Cook pasta al dente\n2. Crisp guanciale in pan\n3. Mix eggs with cheese\n4. Toss hot pasta with egg mixture and guanciale", Ratings = [5, 5, 4, 5] },
        new() { Id = 4, Title = "Chicken Stir Fry", Category = "Dinner", Ingredients = "Chicken breast, Soy sauce, Vegetables, Garlic, Ginger, Rice", Steps = "1. Slice chicken and vegetables\n2. Heat oil in wok\n3. Cook chicken until done\n4. Add vegetables and sauce\n5. Serve over rice", Ratings = [4, 3, 4] },
        new() { Id = 5, Title = "Blueberry Muffins", Category = "Breakfast", Ingredients = "Flour, Sugar, Blueberries, Eggs, Butter, Milk, Baking powder", Steps = "1. Preheat oven to 375°F\n2. Mix dry ingredients\n3. Combine wet ingredients\n4. Fold together, add blueberries\n5. Bake 20-25 minutes", Ratings = [5, 4] },
        new() { Id = 6, Title = "Tomato Soup", Category = "Soups", Ingredients = "Tomatoes, Onion, Garlic, Basil, Cream, Vegetable broth", Steps = "1. Sauté onion and garlic\n2. Add tomatoes and broth\n3. Simmer 20 minutes\n4. Blend until smooth\n5. Stir in cream and basil", Ratings = [4, 4, 5] },
        new() { Id = 7, Title = "Chocolate Chip Cookies", Category = "Desserts", Ingredients = "Flour, Butter, Sugar, Brown sugar, Eggs, Vanilla, Chocolate chips", Steps = "1. Cream butter and sugars\n2. Add eggs and vanilla\n3. Mix in flour\n4. Fold in chocolate chips\n5. Bake at 350°F for 10-12 minutes", Ratings = [5, 5, 5, 4] },
        new() { Id = 8, Title = "Greek Salad", Category = "Salads", Ingredients = "Cucumber, Tomatoes, Red onion, Olives, Feta cheese, Olive oil", Steps = "1. Chop vegetables\n2. Combine in bowl\n3. Add olives and feta\n4. Drizzle with olive oil\n5. Season with oregano", Ratings = [4, 5] },
    ];

    private int _nextId = 9;

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _currentRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="Rate @star stars">
            @(star <= _currentRating ? "★" : "☆")
        </span>
    }
    @if (_rated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }

    private int _currentRating;
    private bool _rated;

    protected override void OnParametersSet()
    {
        _currentRating = (int)Math.Round(AverageRating);
    }

    private void Rate(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        _currentRating = stars;
        _rated = true;
    }
}

.star-rating {
    display: inline-flex;
    align-items: center;
    gap: 0.1rem;
}

.star {
    font-size: 1.5rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.2s;
}

.star:hover,
.star.filled {
    color: #f5a623;
}

@page "/recipes/{Category}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@Category Recipes - RecipeShare</PageTitle>

<h1>@Category</h1>

@if (_recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            @(recipe.Ratings.Count > 0
                                ? $"★ {recipe.AverageRating:F1} ({recipe.Ratings.Count} ratings)"
                                : "No ratings yet")
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter] public string Category { get; set; } = string.Empty;

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@using RecipeShare.Components.Shared
@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (_recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <h1>@_recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@_recipe.Category</span>

    <div class="mb-4">
        <h5>Rate this recipe:</h5>
        <StarRating RecipeId="@_recipe.Id" AverageRating="@_recipe.AverageRating" />
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <div class="card-body">
                    <ul class="mb-0">
                        @foreach (var ingredient in _recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
                        {
                            <li>@ingredient</li>
                        }
                    </ul>
                </div>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Steps</h5></div>
                <div class="card-body">
                    @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <a href="/recipes/@_recipe.Category" class="btn btn-outline-secondary">← Back to @_recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@using System.ComponentModel.DataAnnotations
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted!</h4>
        <p>Your recipe "<strong>@_model.Title</strong>" has been added.</p>
        <a href="/recipe/@_submittedId" class="btn btn-primary">View your recipe</a>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" class="col-md-8">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="_model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="_model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var category in _categories)
                {
                    <option value="@category">@category</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="_model.Ingredients" class="form-control" rows="4"
                           placeholder="Comma-separated: Flour, Sugar, Eggs, Butter" />
            <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="_model.Steps" class="form-control" rows="6"
                           placeholder="One step per line:&#10;1. Preheat oven&#10;2. Mix ingredients&#10;3. Bake for 30 minutes" />
            <ValidationMessage For="() => _model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeModel _model = new();
    private List<string> _categories = [];
    private bool _submitted;
    private int _submittedId;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            Ingredients = _model.Ingredients,
            Steps = _model.Steps
        };
        RecipeService.AddRecipe(recipe);
        _submittedId = recipe.Id;
        _submitted = true;
    }

    private class RecipeModel
    {
        [Required(ErrorMessage = "Please enter a recipe title.")]
        [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3-100 characters.")]
        public string Title { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = string.Empty;
    }
}

