    private int _currentRating;
    private bool _rated;

    protected override void OnParametersSet()
    {
        _currentRating = (int)Math.Round(AverageRating);
    }

    private void Rate(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        _currentRating = stars;
        _rated = true;
    }
}
"}

