toolArgs.file_text:
@page "/recipes/{Category}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@Category Recipes - RecipeShare</PageTitle>

<h1>@Category</h1>

@if (_recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 col-lg-4 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            @(recipe.Ratings.Count > 0
                                ? $"★ {recipe.AverageRating:F1} ({recipe.Ratings.Count} ratings)"
                                : "No ratings yet")
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter] public string Category { get; set; } = string.Empty;

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@using RecipeShare.Components.Shared
@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (_recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <h1>@_recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@_recipe.Category</span>

    <div class="mb-4">
        <h5>Rate this recipe:</h5>
        <StarRating RecipeId="@_recipe.Id" AverageRating="@_recipe.AverageRating" />
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <div class="card-body">
                    <ul class="mb-0">
                        @foreach (var ingredient in _recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
                        {
                            <li>@ingredient</li>
                        }
                    </ul>
                </div>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Steps</h5></div>
                <div class="card-body">
                    @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <a href="/recipes/@_recipe.Category" class="btn btn-outline-secondary">← Back to @_recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@using System.ComponentModel.DataAnnotations
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted!</h4>
        <p>Your recipe "<strong>@_model.Title</strong>" has been added.</p>
        <a href="/recipe/@_submittedId" class="btn btn-primary">View your recipe</a>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" class="col-md-8">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="_model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="_model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var category in _categories)
                {
                    <option value="@category">@category</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="_model.Ingredients" class="form-control" rows="4"
                           placeholder="Comma-separated: Flour, Sugar, Eggs, Butter" />
            <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="_model.Steps" class="form-control" rows="6"
                           placeholder="One step per line:&#10;1. Preheat oven&#10;2. Mix ingredients&#10;3. Bake for 30 minutes" />
            <ValidationMessage For="() => _model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeModel _model = new();
    private List<string> _categories = [];
    private bool _submitted;
    private int _submittedId;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            Ingredients = _model.Ingredients,
            Steps = _model.Steps
        };
        RecipeService.AddRecipe(recipe);
        _submittedId = recipe.Id;
        _submitted = true;
    }

    private class RecipeModel
    {
        [Required(ErrorMessage = "Please enter a recipe title.")]
        [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3-100 characters.")]
        public string Title { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = string.Empty;
    }
}

