namespace RecipeShare.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new() { Id = 1, Title = "Classic Pancakes", Category = "Breakfast", Ingredients = "Flour, Eggs, Milk, Butter, Sugar, Baking powder", Steps = "1. Mix dry ingredients\n2. Whisk wet ingredients\n3. Combine and stir until smooth\n4. Cook on griddle until golden", Ratings = [4, 5, 4] },
        new() { Id = 2, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce, Parmesan, Croutons, Caesar dressing, Lemon", Steps = "1. Wash and chop lettuce\n2. Prepare dressing\n3. Toss lettuce with dressing\n4. Top with croutons and parmesan", Ratings = [5, 4, 5] },
        new() { Id = 3, Title = "Spaghetti Carbonara", Category = "Pasta", Ingredients = "Spaghetti, Eggs, Pecorino Romano, Guanciale, Black pepper", Steps = "1. Cook pasta al dente\n2. Crisp guanciale in pan\n3. Mix eggs with cheese\n4. Toss hot pasta with egg mixture and guanciale", Ratings = [5, 5, 4, 5] },
        new() { Id = 4, Title = "Chicken Stir Fry", Category = "Dinner", Ingredients = "Chicken breast, Soy sauce, Vegetables, Garlic, Ginger, Rice", Steps = "1. Slice chicken and vegetables\n2. Heat oil in wok\n3. Cook chicken until done\n4. Add vegetables and sauce\n5. Serve over rice", Ratings = [4, 3, 4] },
        new() { Id = 5, Title = "Blueberry Muffins", Category = "Breakfast", Ingredients = "Flour, Sugar, Blueberries, Eggs, Butter, Milk, Baking powder", Steps = "1. Preheat oven to 375°F\n2. Mix dry ingredients\n3. Combine wet ingredients\n4. Fold together, add blueberries\n5. Bake 20-25 minutes", Ratings = [5, 4] },
        new() { Id = 6, Title = "Tomato Soup", Category = "Soups", Ingredients = "Tomatoes, Onion, Garlic, Basil, Cream, Vegetable broth", Steps = "1. Sauté onion and garlic\n2. Add tomatoes and broth\n3. Simmer 20 minutes\n4. Blend until smooth\n5. Stir in cream and basil", Ratings = [4, 4, 5] },
        new() { Id = 7, Title = "Chocolate Chip Cookies", Category = "Desserts", Ingredients = "Flour, Butter, Sugar, Brown sugar, Eggs, Vanilla, Chocolate chips", Steps = "1. Cream butter and sugars\n2. Add eggs and vanilla\n3. Mix in flour\n4. Fold in chocolate chips\n5. Bake at 350°F for 10-12 minutes", Ratings = [5, 5, 5, 4] },
        new() { Id = 8, Title = "Greek Salad", Category = "Salads", Ingredients = "Cucumber, Tomatoes, Red onion, Olives, Feta cheese, Olive oil", Steps = "1. Chop vegetables\n2. Combine in bowl\n3. Add olives and feta\n4. Drizzle with olive oil\n5. Season with oregano", Ratings = [4, 5] },
    ];

    private int _nextId = 9;

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }
}

