arguments.new_str:
@page "/"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>RecipeShare - Recipe Community</PageTitle>

<div class="text-center mb-5">
    <h1>🍳 RecipeShare</h1>
    <p class="lead">Discover, share, and rate recipes from our community.</p>
</div>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in _categories)
    {
        <div class="col-md-4 col-sm-6 mb-4">
            <a href="/recipes/@category" class="text-decoration-none">
                <div class="card h-100 text-center border-primary">
                    <div class="card-body">
                        <h4 class="card-title">@category</h4>
                        <p class="card-text text-muted">
                            @(RecipeService.GetByCategory(category).Count) recipe(s)
                        </p>
                    </div>
                </div>
            </a>
        </div>
    }
</div>

<div class="text-center mt-4">
    <a href="/submit" class="btn btn-success btn-lg">📝 Submit Your Recipe</a>
</div>

@code {
    private List<string> _categories = [];

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }
}

